#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 105;
int T,n,m;
int p[N][N],q[N][N];
//在第 i 行中颜色 j 出现的左右边界
int l[N],r[N];
//每种颜色出现的行数范围
bool flag;
//1 表示合法 0 表示不合法
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init(){//预处理
    for(int c=1;c<=n;c++){
        l[c]=m+1,r[c]=0;
        for(int i=1;i<=m;i++)p[i][c]=0,q[i][c]=0;
    }flag=1;return;
}
bool Is_sepa(int x,int y){
    if(!r[x]||!r[y])return 1;
    //判断颜色 x 和 y 是否分离的函数
    if(r[x]<l[y]||r[y]<l[x])return 1;
    //行数没有相交则一定分离
    int now=-1;
    //0 表示 x 在 y 左边，1 表示 x 在 y 右边
    for(int i=max(l[x],l[y]);i<=min(r[x],r[y]);i++){
        //枚举所有相交的函数考虑顺序
        int px=p[i][x],qx=q[i][x];
        int py=p[i][y],qy=q[i][y];
        //取出相应信息方便判断
        int pxy=max(px,py),qxy=min(qx,qy);
        //交集，合法情况下应为 0
        if(pxy<=qxy)return 0;//存在交集，矛盾
        if(qx<py&&now==1)return 0;
        //状态显示 x 在 y 左边，但曾经 x 在 y 右边，矛盾
        if(px>qy&&now==0)return 0;
        //状态显示 x 在 y 右边，但曾经 x 在 y 左边，矛盾
        now=(qx<py?0:1);//更新状态
    }return 1;//合法
}
bool Is_clud(int x,int y){
    if(!r[x]||!r[y])return 1;
    //判断颜色 x 是否包含 y 的函数
    if(l[x]>l[y]||r[y]>r[x])return 0;
    //行数情况不符，不可能包含
    for(int i=l[y];i<=r[y];i++){
        //具体考虑每一行是否都 x 包含 y
        int px=p[i][x],qx=q[i][x];
        int py=p[i][y],qy=q[i][y];
        //cout<<px<<" "<<qx<<"\n";
        //cout<<py<<" "<<qy<<"\n\n";
        //取出相应信息方便判断
        //cout<<(px>py)<<"? "<<(qy>qx)<<"?\n";
        if(px>py||qy>qx)return 0;
        //这一行的包含情况出错
    }return 1;
}
void Sol(){//解决问题的核心函数
    n=read(),m=read();//读入
    init();//多测清空 & 预处理

    for(int i=1;i<=m;i++){
        int k=read();
        for(int j=1;j<=k;j++){
            int c=read();
            l[c]=min(l[c],i),r[c]=max(r[c],i);
            //更新行数情况
            if(!p[i][c])p[i][c]=j;else q[i][c]=j;
            //维护出现位置
        }
    }//读入完毕

//    cout<<"\n";
//
//    for(int c=1;c<=n;c++){
//        cout<<l[c]<<" "<<r[c]<<"\n";
//        for(int i=1;i<=m;i++)
//            cout<<p[i][c]<<" "<<q[i][c]<<"\n";
//        cout<<"\n";
//    }

    for(int c=1;c<=n;c++){//先对每种颜色做最基本的判断
        if(!r[c])continue;
        //这种颜色压根就没出现过（按理来说不应该存在）
        bool ok=1;//判断出现是否连续
        for(int i=l[c];i<=r[c];i++)
            if(!p[i][c]||!q[i][c])ok=0;//没连续
        if(!ok){flag=0;break;}//合法情况不存在了
    }

    for(int x=1;x<n;x++)for(int y=x+1;y<=n;y++)
        flag&=(Is_clud(x,y)||Is_clud(y,x)||Is_sepa(x,y));

    //cout<<"1 clud 2 ? answer : "<<Is_clud(1,2)<<"\n";
    //cout<<"2 clud 1 ? answer : "<<Is_clud(2,1)<<"\n";
    //cout<<"1 sepa 2 ? answer : "<<Is_sepa(1,2)<<"\n";



    //枚举任意两种颜色确保其关系正确（包含或分离）

    if(flag)cout<<"YES\n";else cout<<"NO\n";//依题意输出
}
int main(){
    T=read();
    while(T--)Sol();
    return 0;
}

/*

考虑包含或分离的情况判断。

1. 如何判断是否 x 包含 y？
      首先 x 出现的行数一定要完全包含 y 出现的行数。
      其次在这些行中 x 都严格包含 y。

2. 如何判断 x 和 y 是否分离？
      首先如果它们所出现的行数不相交则显然分离。
      否则枚举它们重合的行数，绝对顺序不能错。

大概就是这样了。

